import React from 'react';
import { Breadcrumb } from 'antd';
import { Link } from 'react-router-dom';
import BreadCrumbStyle from './breadCrumbStyle.js';

const BreadCrumb = (props) =>{
    let len=props.urlList.length;

    const handleOnClick = (obj, index) => {
        if(props.handleOnClick){
            props.handleOnClick(obj, index);
        }
    }


    return (
        <>
        <BreadCrumbStyle/>
        <div className='bread-crumb-bar'>
            <div className='bread-crumb-left'>
            {/* className={classCSS.separator} */}
                <Breadcrumb separator={<div style={{fontFamily: 'Roboto', fontStyle: 'normal', fontWeight: 'normal', fontSize: '14px', lineHeight: '22px', color: '#727272', display: 'contents'}}>/</div>} >
                    {props.urlList.map((obj,index) => (
                    <Breadcrumb.Item key={obj.id} onClick={() => handleOnClick(obj, index)}>
                        <Link
                            to={obj.url}
                            className =  { len === index+1 ? 'font-family-weight-500 fs14 ls22 color_212121 display_content capital_first_letter' : 'font-family-weight-normal fs14 ls22 color_727272 display_content capital_first_letter'}
                            >{obj.heading}
                        </Link>
                    </Breadcrumb.Item>
                    ))}
                </Breadcrumb>
            </div>
            <div className='bread-crumb-right'>
            {props.rightItem}
            </div>
            
        </div>
        </>
    );   
};

export default BreadCrumb;